import React from 'react';
import * as PopoverPrimitive from '@radix-ui/react-popover';
import { Direction, readDirection } from '@/utils/dir-helper.util';

import { cn } from '@/utils/shadcn-ui.util';
import { Z_INDEX_ABOVE_DOCK } from '@/components/z-index';

/**
 * The Popover component displays rich content in a portal, triggered by a button. This popover is
 * built on Radix UI's Popover component and styled by Shadcn UI.
 *
 * See Shadcn UI Documentation https://ui.shadcn.com/docs/components/popover See Radix UI
 * Documentation https://www.radix-ui.com/docs/primitives/components/popover
 */
const Popover = PopoverPrimitive.Root;

/** @inheritdoc Popover */
const PopoverTrigger = PopoverPrimitive.Trigger;

/** @inheritdoc Popover */
const PopoverAnchor = PopoverPrimitive.Anchor;

/** @inheritdoc Popover */
function PopoverContent({
  className,
  align = 'center',
  sideOffset = 4,
  style,
  ref,
  ...props
}: React.ComponentPropsWithoutRef<typeof PopoverPrimitive.Content> & {
  ref?: React.Ref<React.ComponentRef<typeof PopoverPrimitive.Content>>;
}) {
  const dir: Direction = readDirection();
  return (
    <PopoverPrimitive.Portal>
      <PopoverPrimitive.Content
        ref={ref}
        align={align}
        sideOffset={sideOffset}
        className={cn(
          // CUSTOM removed tw:z-50 to use const below
          'pr-twp tw:w-72 tw:rounded-md tw:border tw:bg-popover tw:p-4 tw:text-popover-foreground tw:shadow-md tw:outline-none tw:data-[state=open]:animate-in tw:data-[state=closed]:animate-out tw:data-[state=closed]:fade-out-0 tw:data-[state=open]:fade-in-0 tw:data-[state=closed]:zoom-out-95 tw:data-[state=open]:zoom-in-95 tw:data-[side=bottom]:slide-in-from-top-2 tw:data-[side=left]:slide-in-from-right-2 tw:data-[side=right]:slide-in-from-left-2 tw:data-[side=top]:slide-in-from-bottom-2',
          className,
        )}
        // CUSTOM z-index uses shared constant instead of default tw:z-50
        style={{ zIndex: Z_INDEX_ABOVE_DOCK, ...style }}
        {...props}
        dir={dir}
      />
    </PopoverPrimitive.Portal>
  );
}

export { Popover, PopoverTrigger, PopoverContent, PopoverAnchor };
